SELECT COUNT(DISTINCT injury_id) AS total_injuries
FROM player_injuries
WHERE player_id = (SELECT player_id FROM players WHERE first_name = 'Michael' AND last_name = 'Jordan');

SELECT games_missed, player_id
FROM player_injuries
ORDER BY games_missed DESC;

SELECT MAX(wins) AS highest_victories
FROM team_coaches
WHERE team_id = 1;
